import{_ as a,o as e,c as t,a5 as i}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：Boost 慢速任务、遥测与故障日志","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：Boost 慢速任务、遥测与故障日志","tags":["power-electronics"],"status":"learning","summary":"慢速任务（slow task）是相对控制中断服务程序（control interrupt service routine / control ISR）而言的低频软件任务。它不直接决定每个开关周期的占空比，而是周期性整理运行数据。"},"headers":[],"relativePath":"content/power/concepts/embedded/boost-telemetry-fault-log.md","filePath":"content/power/concepts/embedded/boost-telemetry-fault-log.md","lastUpdated":null}'),l={name:"content/power/concepts/embedded/boost-telemetry-fault-log.md"};function o(n,s,p,h,r,d){return e(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="概念-boost-慢速任务、遥测与故障日志" tabindex="-1">概念：Boost 慢速任务、遥测与故障日志 <a class="header-anchor" href="#概念-boost-慢速任务、遥测与故障日志" aria-label="Permalink to &quot;概念：Boost 慢速任务、遥测与故障日志&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>慢速任务（slow task）是相对控制中断服务程序（control interrupt service routine / control ISR）而言的低频软件任务。它不直接决定每个开关周期的占空比，而是周期性整理运行数据。</p><p>遥测（telemetry）是把关键运行变量打包出来，供上位机、显示屏或通信接口读取。</p><p>故障日志（fault log）是在故障发生时记录关键证据，例如时间、故障码、电压、电流和输出使能状态。</p><p>本节仍使用教学模型，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据；学习记录中也不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_2-ups-为什么需要它" tabindex="-1">2. UPS 为什么需要它 <a class="header-anchor" href="#_2-ups-为什么需要它" aria-label="Permalink to &quot;2. UPS 为什么需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）不仅要实时控制，还要能被调试、维护和诊断。控制 ISR 负责快，慢速任务负责看得见、说得清、留得住。</p><ul><li>看得见：遥测把电压、电流、状态、PWM 使能等变量送到通信接口。</li><li>说得清：故障日志给导师或调试人员提供证据。</li><li>留得住：故障发生后，即使波形已经过去，日志仍记录发生时刻和关键变量。</li></ul><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>控制 ISR 像开车时每一瞬间的方向盘动作，慢速任务像仪表盘和行车记录。方向盘必须快，仪表盘可以慢一些，但出事故时必须留下发生时刻、速度和报警状态。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>两个周期：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T_control = 1 / f_control</span></span>
<span class="line"><span>T_telemetry = 1 / f_telemetry</span></span></code></pre></div><p>通常 <code>f_control</code> 远高于 <code>f_telemetry</code>。例如本节：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>f_control = 10 kHz</span></span>
<span class="line"><span>f_telemetry = 100 Hz</span></span></code></pre></div><p>故障日志采用边沿触发思想：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if fault_now and not fault_logged:</span></span>
<span class="line"><span>    write_log(time, fault_code, Vout, pwm_enable)</span></span></code></pre></div><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>一个仿真任务是运行 <code>boost_telemetry_fault_log.py</code>，同时检查图片和 CSV 两个产物：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_telemetry_fault_log.py</span></span></code></pre></div><p>对比遥测频率：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_telemetry_fault_log.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">telemetry</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">frequency </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">50</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_telemetry_50hz.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">csv</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_fault_log_50hz.csv </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_telemetry_fault_log.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">telemetry</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">frequency </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">500</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_telemetry_500hz.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">csv</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_fault_log_500hz.csv </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>脚本会生成：</p><ul><li>图：<code>simulations/results/boost_telemetry_fault_log.png</code></li><li>故障日志 CSV：<code>simulations/results/boost_fault_log.csv</code></li></ul><p>图中可以看到控制周期电压、慢速遥测采样点、PWM 使能和故障事件标记。CSV 中记录了故障事件的具体证据。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实工程中，慢速任务可能包括：</p><ul><li><code>telemetry.c</code>：打包电压、电流、状态、故障码。</li><li><code>log.c</code>：记录故障事件。</li><li><code>communication.c</code>：通过串口、控制器局域网（controller area network / CAN）或其他接口发出数据。</li><li><code>parameter.c</code>：处理参数读取、限幅和保存。</li></ul><p>读代码时要区分“实时控制路径”和“观测记录路径”。慢速任务不应该阻塞控制 ISR。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：通信和日志是后期锦上添花。<br> 正确理解：没有遥测和日志，调试保护和状态机问题会非常困难。</p></li><li><p>错误理解：慢速任务可以读取任何变量，不用考虑一致性。<br> 正确理解：跨中断共享变量要考虑快慢任务之间的数据一致性。</p></li><li><p>错误理解：故障日志只需要故障码。<br> 正确理解：故障码之外，还应记录时间、关键采样值和输出状态。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释慢速任务（slow task）和控制 ISR 的分工。</li><li>能解释遥测（telemetry）与故障日志（fault log）的区别。</li><li>能打开 <code>boost_fault_log.csv</code> 并指出故障时间、故障码、电压和 PWM 使能。</li><li>能解释为什么故障日志采用边沿触发，不每个周期重复写。</li><li>能基于图和 CSV 准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>默认仿真中，控制频率和遥测频率分别是多少？两者相差多少倍？</li><li>故障日志 CSV 里记录的 <code>time_ms</code> 是多少？对应图中的哪个故障标记？</li><li>把 <code>--telemetry-frequency</code> 从 50 改成 500 后，图中哪类点变化最明显？</li><li>如果遥测频率太低，是否一定会漏掉故障？为什么故障日志仍然重要？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>boost_telemetry_fault_log.py</code> 生成了 <code>boost_fault_log.csv</code>，里面记录故障时间、电压和 PWM 使能。公司工程里故障日志通常记录哪些字段？</li><li>我看到控制频率是 10 kHz，遥测频率是 100 Hz。真实工程里通信任务和控制 ISR 的频率通常如何分配？</li><li>如果慢速任务读取 ISR 更新的变量，公司代码里通常如何保证数据一致性？</li></ul>`,38)])])}const u=a(l,[["render",o]]);export{k as __pageData,u as default};
